#!/usr/bin/env node

var fs = require('fs');
var path = require('path');

var localFile   = path.normalize(__dirname + '/../config/identity.js');
var folder      = path.normalize(process.cwd() + '/../../config/');
var projectFile = path.normalize(process.cwd() + '/../../config/identity.js');

if(!fs.existsSync(projectFile) && fs.existsSync(folder)){
  console.log("coppying " + localFile + " to " + projectFile)
  fs.createReadStream(localFile).pipe(fs.createWriteStream(projectFile));
}